import React from 'react';
import { describe, expect, it, vi } from 'vitest';
import { fireEvent, render, screen } from '@testing-library/react';
import { TooltipProvider } from '../../../src/webview/components/ui/overlay/tooltip';
import { PluginToolbarActionMenu } from '../../../src/webview/components/toolbar/PluginMenu';

vi.mock('../../../src/webview/components/ui/menus/dropdown-menu', () => {
  const DropdownMenuTrigger = React.forwardRef<HTMLDivElement, { children: React.ReactNode }>(
    ({ children }, ref) => <div ref={ref}>{children}</div>,
  );
  DropdownMenuTrigger.displayName = 'DropdownMenuTrigger';

  const DropdownMenuContent = React.forwardRef<HTMLDivElement, { children: React.ReactNode }>(
    ({ children }, ref) => (
      <div ref={ref} data-testid="dropdown-content">{children}</div>
    ),
  );
  DropdownMenuContent.displayName = 'DropdownMenuContent';

  const DropdownMenuItem = React.forwardRef<
    HTMLButtonElement,
    { children: React.ReactNode; onSelect?: () => void }
  >(({ children, onSelect }, ref) => (
    <button ref={ref} type="button" onClick={onSelect}>
      {children}
    </button>
  ));
  DropdownMenuItem.displayName = 'DropdownMenuItem';

  return {
    DropdownMenu: ({ children }: { children: React.ReactNode }) => <div>{children}</div>,
    DropdownMenuTrigger,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuLabel: ({ children }: { children: React.ReactNode }) => (
      <span data-testid="dropdown-label">{children}</span>
    ),
  };
});

describe('webview/toolbar/PluginMenu', () => {
  it('renders plugin action items and posts the selected action', () => {
    const postMessageSpy = vi.spyOn(window, 'postMessage').mockImplementation(() => undefined);

    render(
      <TooltipProvider>
        <PluginToolbarActionMenu
          action={{
            id: 'wikilinks',
            label: 'Docs',
            pluginId: 'plugin.docs',
            pluginName: 'Docs Plugin',
            index: 0,
            items: [{ id: 'docs-summary', label: 'Docs Summary', index: 0 }],
          }}
        />
      </TooltipProvider>,
    );

    fireEvent.click(screen.getByText('Docs Summary'));

    expect(postMessageSpy).toHaveBeenCalledWith({
      type: 'RUN_PLUGIN_TOOLBAR_ACTION',
      payload: {
        pluginId: 'plugin.docs',
        index: 0,
        itemIndex: 0,
      },
    }, '*');

    postMessageSpy.mockRestore();
  });
});

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, screen, fireEvent } from '@testing-library/react';
import { TooltipProvider } from '../../../src/webview/components/ui/overlay/tooltip';
import { graphStore } from '../../../src/webview/store/state';

vi.mock('../../../src/webview/vscodeApi', () => ({
  postMessage: vi.fn(),
}));

import { postMessage } from '../../../src/webview/vscodeApi';
import { DepthModeToggle } from '../../../src/webview/components/toolbar/DepthModeToggle';

function renderWithProviders() {
  return render(
    <TooltipProvider>
      <DepthModeToggle />
    </TooltipProvider>,
  );
}

describe('DepthModeToggle', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    graphStore.setState({
      depthMode: false,
      graphHasIndex: false,
    });
  });

  it('renders a disabled button before the repo has been indexed', () => {
    renderWithProviders();

    expect(screen.getByTitle('Enable Depth Mode')).toBeDisabled();
  });

  it('enables depth mode when clicked after indexing', () => {
    graphStore.setState({ graphHasIndex: true });
    renderWithProviders();

    fireEvent.click(screen.getByTitle('Enable Depth Mode'));

    expect(postMessage).toHaveBeenCalledWith({
      type: 'UPDATE_DEPTH_MODE',
      payload: { depthMode: true },
    });
  });

  it('disables depth mode when clicked while already active', () => {
    graphStore.setState({
      depthMode: true,
      graphHasIndex: true,
    });
    renderWithProviders();

    fireEvent.click(screen.getByTitle('Disable Depth Mode'));

    expect(postMessage).toHaveBeenCalledWith({
      type: 'UPDATE_DEPTH_MODE',
      payload: { depthMode: false },
    });
  });

  it('uses the active button variant while depth mode is enabled', () => {
    graphStore.setState({
      depthMode: true,
      graphHasIndex: true,
    });
    renderWithProviders();

    expect(screen.getByTitle('Disable Depth Mode').className).toContain('hover:bg-primary/90');
  });
});

import React from 'react';
import { describe, expect, it, vi, beforeEach } from 'vitest';
import { fireEvent, render, screen } from '@testing-library/react';
import { IndexToolbarAction } from '../../../src/webview/components/toolbar/IndexAction';

const clearPendingIndexTimeout = vi.fn();
const createRefreshConfig = vi.fn();
const requestGraphIndex = vi.fn();
const buttonProps: Array<Record<string, unknown>> = [];

vi.mock('../../../src/webview/components/toolbar/refresh', () => ({
  clearPendingIndexTimeout: (...args: unknown[]) => clearPendingIndexTimeout(...args),
  createRefreshConfig: (...args: unknown[]) => createRefreshConfig(...args),
  requestGraphIndex: (...args: unknown[]) => requestGraphIndex(...args),
}));

vi.mock('../../../src/webview/components/toolbar/IconButton', () => ({
  ToolbarIconButton: (props: {
    disabled?: boolean;
    title: string;
    onClick: () => void;
  }) => {
    buttonProps.push(props as unknown as Record<string, unknown>);
    return (
      <button
        type="button"
        disabled={props.disabled}
        onClick={props.onClick}
        title={props.title}
      >
        {props.title}
      </button>
    );
  },
}));

describe('webview/toolbar/IndexAction', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    buttonProps.length = 0;
    createRefreshConfig.mockImplementation((graphHasIndex: boolean) => (
      graphHasIndex
        ? { phase: 'Refreshing Index', title: 'Refresh', type: 'REFRESH_GRAPH' }
        : { phase: 'Indexing Repo', title: 'Index Repo', type: 'INDEX_GRAPH' }
    ));
  });

  it('renders the configured title and disabled state', () => {
    render(<IndexToolbarAction graphHasIndex graphIsIndexing />);

    expect(createRefreshConfig).toHaveBeenCalledWith(true);
    expect(screen.getByTitle('Refresh')).toBeDisabled();
  });

  it('requests a graph index with the current graphHasIndex flag when clicked', () => {
    render(<IndexToolbarAction graphHasIndex={false} graphIsIndexing={false} />);

    fireEvent.click(screen.getByTitle('Index Repo'));

    expect(requestGraphIndex).toHaveBeenCalledTimes(1);
    expect(requestGraphIndex.mock.calls[0][0]).toBe(false);
    expect(requestGraphIndex.mock.calls[0][1]).toMatchObject({ current: null });
  });

  it('clears the pending timeout when indexing stops after a rerender', () => {
    const { rerender } = render(<IndexToolbarAction graphHasIndex graphIsIndexing />);

    rerender(<IndexToolbarAction graphHasIndex graphIsIndexing={false} />);

    expect(clearPendingIndexTimeout).toHaveBeenCalledTimes(1);
    expect(clearPendingIndexTimeout.mock.calls[0][0]).toMatchObject({ current: null });
  });

  it('clears the pending timeout when the component unmounts', () => {
    const { unmount } = render(<IndexToolbarAction graphHasIndex={false} graphIsIndexing={false} />);
    const callsBeforeUnmount = clearPendingIndexTimeout.mock.calls.length;

    unmount();

    expect(clearPendingIndexTimeout.mock.calls.length).toBe(callsBeforeUnmount + 1);
    expect(clearPendingIndexTimeout.mock.calls.at(-1)?.[0]).toMatchObject({ current: null });
  });
});

